// Execute command with timing and error handling
function exec(command, options = {}) {
  const {
    cwd = process.cwd(),
    env = process.env,
    silent = false,
    ignoreError = false,
    timeout = 300000, // 5 min default
  } = options;

  const startTime = Date.now();

  if (!silent) {
    log(`$ ${command}`, 'blue');
  }

  try {
    const result = execSync(command, {
      cwd,
      env: { ...env, FORCE_COLOR: '1' },
      stdio: silent ? 'pipe' : 'inherit',
      timeout,
      encoding: 'utf-8',
    });

    const duration = ((Date.now() - startTime) / 1000).toFixed(2);
    if (!silent) {
      log(`Command completed in ${duration}s`, 'green');
    }

    return { success: true, output: result, duration: parseFloat(duration) };
  } catch (error) {
    const duration = ((Date.now() - startTime) / 1000).toFixed(2);

    if (ignoreError) {
      logWarning(`Command failed (ignored) in ${duration}s: ${command}`);
      return { success: false, output: error.stdout || '', error: error.message, duration: parseFloat(duration) };
    }

    throw new PipelineError(`Command failed after ${duration}s: ${command}`, error);
  }
}

// Execute command asynchronously
function execAsync(command, options = {}) {
  return new Promise((resolve, reject) => {
    const {
      cwd = process.cwd(),
      env = process.env,
      timeout = 300000,
    } = options;

    const startTime = Date.now();
    log(`$ ${command} (async)`, 'blue');

    const child = spawn('sh', ['-c', command], {
      cwd,
      env: { ...env, FORCE_COLOR: '1' },
      stdio: 'pipe',
      timeout,
    });

    let stdout = '';
    let stderr = '';

    child.stdout.on('data', (data) => { stdout += data.toString(); });
    child.stderr.on('data', (data) => { stderr += data.toString(); });

    child.on('close', (code) => {
      const duration = ((Date.now() - startTime) / 1000).toFixed(2);
      if (code === 0) {
        resolve({ success: true, output: stdout, duration: parseFloat(duration) });
      } else {
        reject(new PipelineError(`Async command failed (exit ${code}): ${command}\n${stderr}`));
      }
    });

    child.on('error', (err) => {
      reject(new PipelineError(`Failed to start command: ${command}`, err));
    });
  });
}

class PipelineError extends Error {
  constructor(message, cause) {
    super(message);
    this.name = 'PipelineError';
    this.cause = cause;
  }
}

// Stage runner with timing
async function runStage(name, fn) {
  logStage(name);
  const stage = { name, startTime: Date.now(), status: 'running' };
  pipelineState.currentStage = name;
  pipelineState.stages.push(stage);

  try {
    await fn();
    stage.status = 'success';
    stage.duration = ((Date.now() - stage.startTime) / 1000).toFixed(2);
    logSuccess(`Stage "${name}" completed in ${stage.duration}s`);
  } catch (error) {
    stage.status = 'failed';
    stage.duration = ((Date.now() - stage.startTime) / 1000).toFixed(2);
    stage.error = error.message;
    logError(`Stage "${name}" failed after ${stage.duration}s: ${error.message}`);
    throw error;
  }
}

// Check environment prerequisites
async function stagePreflightChecks() {
  // Check Node.js version
  const nodeVersion = process.version;
  log(`Node.js version: ${nodeVersion}`);

  // Check for required files
  const requiredFiles = ['package.json'];
  for (const file of requiredFiles) {
    if (!fs.existsSync(file)) {
      throw new PipelineError(`Required file not found: ${file}`);
    }
  }
  logSuccess('package.json found');

  // Read package.json for project info
  const pkg = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
  log(`Project: ${pkg.name}@${pkg.version}`);

  // Check available scripts
  const scripts = pkg.scripts || {};
  log(`Available scripts: ${Object.keys(scripts).join(', ')}`);

  // Generate build hash from git
  try {
    const gitHash = exec('git rev-parse --short HEAD', { silent: true });
    pipelineState.buildHash = gitHash.output.trim();
    log(`Build hash: ${pipelineState.buildHash}`);

    const gitBranch = exec('git rev-parse --abbrev-ref HEAD', { silent: true });
    log(`Branch: ${gitBranch.output.trim()}`);

    // Check for uncommitted changes
    const gitStatus = exec('git status --porcelain', { silent: true });
    if (gitStatus.output.trim()) {
      logWarning('Working directory has uncommitted changes');
    }
  } catch {
    logWarning('Git not available - skipping git info');
    pipelineState.buildHash = Date.now().toString(36);
  }

  // Check disk space
  try {
    const dfResult = exec('df -h . | tail -1', { silent: true });
    log(`Disk space: ${dfResult.output.trim()}`);
  } catch {
    // Non-critical
  }

  // Check for lockfile (determines package manager)
  const packageManager = detectPackageManager();
  log(`Package manager: ${packageManager}`);

  // Verify package manager is installed
  exec(`${packageManager} --version`, { silent: true });
  logSuccess(`${packageManager} is available`);

  // Create artifact directory
  if (!fs.existsSync(CONFIG.artifactDir)) {
    fs.mkdirSync(CONFIG.artifactDir, { recursive: true });
  }
}

function detectPackageManager() {
  if (fs.existsSync('pnpm-lock.yaml')) return 'pnpm';
  if (fs.existsSync('yarn.lock')) return 'yarn';
  if (fs.existsSync('bun.lockb')) return 'bun';
  return 'npm';
}

function getInstallCommand(pm) {
  switch (pm) {
    case 'pnpm': return 'pnpm install --frozen-lockfile --prefer-offline';
    case 'yarn': return 'yarn install --frozen-lockfile --prefer-offline';
    case 'bun': return 'bun install --frozen-lockfile';
    default: return 'npm ci --prefer-offline';
  }
}

function getRunCommand(pm, script) {
  switch (pm) {
    case 'pnpm': return `pnpm run ${script}`;
    case 'yarn': return `yarn ${script}`;
    case 'bun': return `bun run ${script}`;
    default: return `npm run ${script}`;
  }
}

// Install dependencies with caching
async function stageInstallDependencies() {
  const pm = detectPackageManager();

  // Setup cache directory
  if (!fs.existsSync(CONFIG.npmCacheDir)) {
    fs.mkdirSync(CONFIG.npmCacheDir, { recursive: true });
  }

  // Check if node_modules matches lockfile (skip install if unchanged)
  const lockfileHash = computeFileHash(getLockfileName(pm));
  const cacheMarker = path.join('node_modules', '.cache-marker');

  if (fs.existsSync(cacheMarker)) {
    const cachedHash = fs.readFileSync(cacheMarker, 'utf-8').trim();
    if (cachedHash === lockfileHash) {
      logSuccess('Dependencies unchanged - skipping install (cache hit)');
      return;
    }
  }

  log('Installing dependencies...');

  const installCmd = getInstallCommand(pm);

  // Set cache config for npm
  const env = { ...process.env };
  if (pm === 'npm') {
    env.npm_config_cache = CONFIG.npmCacheDir;
  } else if (pm === 'pnpm') {
    env.npm_config_store_dir = path.join(CONFIG.npmCacheDir, 'pnpm-store');
  }

  exec(installCmd, { env });

  // Write cache marker
  fs.writeFileSync(cacheMarker, lockfileHash);

  // Verify installation
  const nodeModulesExists = fs.existsSync('node_modules');
  if (!nodeModulesExists) {
    throw new PipelineError('node_modules directory not found after install');
  }

  logSuccess('Dependencies installed successfully');
}

function getLockfileName(pm) {
  switch (pm) {
    case 'pnpm': return 'pnpm-lock.yaml';
    case 'yarn': return 'yarn.lock';
    case 'bun': return 'bun.lockb';
    default: return 'package-lock.json';
  }
}

function computeFileHash(filePath) {
  if (!fs.existsSync(filePath)) return 'none';
  const crypto = require('crypto');
  const content = fs.readFileSync(filePath);
  return crypto.createHash('md5').update(content).digest('hex');
}

// Code quality checks (linting, type checking)
async function stageCodeQuality() {
  const pm = detectPackageManager();
  const pkg = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
  const scripts = pkg.scripts || {};

  const checks = [];

  // Run lint if available
  if (scripts.lint) {
    checks.push(execAsync(getRunCommand(pm, 'lint')).catch((err) => {
      logWarning(`Linting failed: ${err.message}`);
      return { success: false };
    }));
  } else {
    logWarning('No lint script found - skipping');
  }

  // Run type checking if available
  if (scripts['type-check'] || scripts.typecheck) {
    const typeScript = scripts['type-check'] ? 'type-check' : 'typecheck';
    checks.push(execAsync(getRunCommand(pm, typeScript)).catch((err) => {
      logWarning(`Type checking failed: ${err.message}`);
      return { success: false };
    }));
  } else if (fs.existsSync('tsconfig.json')) {
    checks.push(execAsync('npx tsc --noEmit').catch((err) => {
      logWarning(`TypeScript check failed: ${err.message}`);
      return { success: false };
    }));
  }

  // Security audit (non-blocking)
  if (pm === 'npm') {
    checks.push(execAsync('npm audit --production --audit-level=high', { timeout: 30000 }).catch((err) => {
      logWarning(`Security audit found issues: ${err.message}`);
      return { success: false };
    }));
  }

  if (checks.length === 0) {
    logWarning('No code quality checks configured');
    return;
  }

  const results = await Promise.allSettled(checks);
  const failures = results.filter(r => r.status === 'rejected');

  if (failures.length > 0) {
    logWarning(`${failures.length} code quality check(s) had issues`);
  }

  logSuccess('Code quality checks completed');
}

// Run tests with retry logic
async function stageRunTests() {
  const pm = detectPackageManager();
  const pkg = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
  const scripts = pkg.scripts || {};

  if (!scripts.test) {
    logWarning('No test script found - skipping tests');
    return;
  }

  // Set test environment
  const env = {
    ...process.env,
    NODE_ENV: 'test',
    CI: 'true',
    JEST_JUNIT_OUTPUT_DIR: CONFIG.artifactDir,
    JEST_JUNIT_OUTPUT_NAME: 'test-results.xml',
  };

  let testPassed = false;
  let lastError = null;

  for (let attempt = 1; attempt <= CONFIG.testRetries; attempt++) {
    if (attempt > 1) {
      logWarning(`Retrying tests (attempt ${attempt}/${CONFIG.testRetries})...`);
    }

    try {
      // Run tests with coverage
      const testCmd = scripts['test:ci']
        ? getRunCommand(pm, 'test:ci')
        : `${getRunCommand(pm, 'test')} -- --coverage --forceExit --detectOpenHandles`;

      exec(testCmd, { env, timeout: 600000 }); // 10 min timeout for tests
      testPassed = true;
      break;
    } catch (error) {
      lastError = error;
      logWarning(`Test attempt ${attempt} failed: ${error.message}`);
    }
  }

  if (!testPassed) {
    throw new PipelineError(`Tests failed after ${CONFIG.testRetries} attempts`, lastError);
  }

  // Copy coverage artifacts if they exist
  const coverageDir = path.join('coverage');
  if (fs.existsSync(coverageDir)) {
    const coverageSummaryPath = path.join(coverageDir, 'coverage-summary.json');
    if (fs.existsSync(coverageSummaryPath)) {
      const summary = JSON.parse(fs.readFileSync(coverageSummaryPath, 'utf-8'));
      const total = summary.total;
      if (total) {
        log(`Coverage - Lines: ${total.lines?.pct || 'N/A'}% | Branches: ${total.branches?.pct || 'N/A'}% | Functions: ${total.functions?.pct || 'N/A'}%`);
      }
    }
    // Copy coverage to artifacts
    exec(`cp -r coverage ${CONFIG.artifactDir}/`, { silent: true, ignoreError: true });
  }

  logSuccess('All tests passed');
}

// Build the application
async function stageBuild() {
  const pm = detectPackageManager();
  const pkg = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
  const scripts = pkg.scripts || {};

  if (!scripts.build) {
    logWarning('No build script found - skipping build');
    return;
  }

  // Clean previous build
  if (fs.existsSync(CONFIG.buildDir)) {
    log(`Cleaning previous build directory: ${CONFIG.buildDir}`);
    fs.rmSync(CONFIG.buildDir, { recursive: true, force: true });
  }

  // Set production environment for build
  const env = {
    ...process.env,
    NODE_ENV: 'production',
    BUILD_HASH: pipelineState.buildHash,
    BUILD_TIME: new Date().toISOString(),
  };

  // Run build
  exec(getRunCommand(pm, 'build'), { env, timeout: 600000 }); // 10 min timeout

  // Verify build output exists
  if (!fs.existsSync(CONFIG.buildDir)) {
    throw new PipelineError(`Build directory "${CONFIG.buildDir}" not found after build`);
  }

  // Calculate build size
  const buildSize = getDirectorySize(CONFIG.buildDir);
  log(`Build size: ${formatBytes(buildSize)}`);

  // Write build manifest
  const manifest = {
    version: pkg.version,
    name: pkg.name,
    buildHash: pipelineState.buildHash,
    buildTime: new Date().toISOString(),
    buildSize: buildSize,
    nodeVersion: process.version,
  };

  fs.writeFileSync(
    path.join(CONFIG.buildDir, 'build-manifest.json'),
    JSON.stringify(manifest, null, 2)
  );

  // Create compressed artifact
  const artifactName = `${pkg.name}-${pkg.version}-${pipelineState.buildHash}.tar.gz`;
  const artifactPath = path.join(CONFIG.artifactDir, artifactName);
  exec(`tar -czf ${artifactPath} -C ${CONFIG.buildDir} .`, { silent: true });
  const artifactSize = fs.statSync(artifactPath).size;
  log(`Artifact created: ${artifactName} (${formatBytes(artifactSize)})`);

  logSuccess('Build completed successfully');
}

function getDirectorySize(dirPath) {
  let size = 0;
  const entries = fs.readdirSync(dirPath, { withFileTypes: true });
  for (const entry of entries) {
    const fullPath = path.join(dirPath, entry.name);
    if (entry.isDirectory()) {
      size += getDirectorySize(fullPath);
    } else {
      size += fs.statSync(fullPath).size;
    }
  }
  return size;
}

function formatBytes(bytes) {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

// Deploy to production
async function stageDeploy() {
  const deployTarget = CONFIG.deployTarget;

  log(`Deploying to: ${deployTarget}`);
  log(`Deploy host: ${CONFIG.deployHost || 'localhost'}`);

  if (!CONFIG.deployHost) {
    // Local deployment
    await deployLocal();
  } else {
    // Remote deployment via SSH
    await deployRemote();
  }

  logSuccess('Deployment completed');
}

async function deployLocal() {
  const deployPath = CONFIG.deployPath;
  const releasePath = path.join(deployPath, 'releases', pipelineState.buildHash);
  const currentLink = path.join(deployPath, 'current');

  // Save previous deployment hash for rollback
  if (fs.existsSync(currentLink)) {
    try {
      const currentTarget = fs.readlinkSync(currentLink);
      pipelineState.previousDeployHash = path.basename(currentTarget);
      log(`Previous deployment: ${pipelineState.previousDeployHash}`);
    } catch {
      // Not a symlink, continue
    }
  }

  // Create release directory
  log(`Creating release directory: ${releasePath}`);
  fs.mkdirSync(releasePath, { recursive: true });

  // Copy build to release
  exec(`cp -r ${CONFIG.buildDir}/* ${releasePath}/`);

  // Copy production dependencies if applicable
  if (fs.existsSync('package.json')) {
    exec(`cp package.json ${releasePath}/`);
    if (fs.existsSync('package-lock.json')) {
      exec(`cp package-lock.json ${releasePath}/`);
    }

    // Install production-only dependencies in release dir
    const pm = detectPackageManager();
    if (pm === 'npm') {
      exec('npm ci --production --prefer-offline', { cwd: releasePath });
    } else if (pm === 'pnpm') {
      exec('pnpm install --prod --frozen-lockfile', { cwd: releasePath });
    } else if (pm === 'yarn') {
      exec('yarn install --production --frozen-lockfile', { cwd: releasePath });
    }
  }

  // Atomic symlink switch
  const tmpLink = `${currentLink}.tmp`;
  log('Switching symlink atomically...');

  try {
    if (fs.existsSync(tmpLink)) fs.unlinkSync(tmpLink);
    fs.symlinkSync(releasePath, tmpLink);
    fs.renameSync(tmpLink, currentLink);
    logSuccess(`Symlink updated: current -> ${pipelineState.buildHash}`);
  } catch (error) {
    // Cleanup temp link on failure
    if (fs.existsSync(tmpLink)) fs.unlinkSync(tmpLink);
    throw new PipelineError('Failed to switch deployment symlink', error);
  }

  // Cleanup old releases (keep last 5)
  await cleanupOldReleases(path.join(deployPath, 'releases'), 5);

  // Restart application service if applicable
  await restartService();
}

async function deployRemote() {
  const { deployHost, deployUser, deployPath } = CONFIG;
  const ssh = `ssh -o StrictHostKeyChecking=no ${deployUser}@${deployHost}`;
  const releasePath = `${deployPath}/releases/${pipelineState.buildHash}`;
  const currentLink = `${deployPath}/current`;

  // Get previous deployment hash
  try {
    const result = exec(`${ssh} "readlink ${currentLink} | xargs basename"`, { silent: true, ignoreError: true });
    if (result.success) {
      pipelineState.previousDeployHash = result.output.trim();
      log(`Previous deployment: ${pipelineState.previousDeployHash}`);
    }
  } catch {
    // No previous deployment
  }

  // Create release directory on remote
  exec(`${ssh} "mkdir -p ${releasePath}"`);

  // Find the artifact to deploy
  const pkg = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
  const artifactName = `${pkg.name}-${pkg.version}-${pipelineState.buildHash}.tar.gz`;
  const artifactPath = path.join(CONFIG.artifactDir, artifactName);

  if (!fs.existsSync(artifactPath)) {
    throw new PipelineError(`Deploy artifact not found: ${artifactPath}`);
  }

  // Upload artifact
  log('Uploading artifact to remote...');
  exec(`scp -o StrictHostKeyChecking=no ${artifactPath} ${deployUser}@${deployHost}:${releasePath}/`);

  // Extract artifact on remote
  exec(`${ssh} "cd ${releasePath} && tar -xzf ${artifactName} && rm ${artifactName}"`);

  // Copy package files and install production deps
  if (fs.existsSync('package.json')) {
    exec(`scp -o StrictHostKeyChecking=no package.json ${deployUser}@${deployHost}:${releasePath}/`);
    const lockfile = getLockfileName(detectPackageManager());
    if (fs.existsSync(lockfile)) {
      exec(`scp -o StrictHostKeyChecking=no ${lockfile} ${deployUser}@${deployHost}:${releasePath}/`);
    }
    exec(`${ssh} "cd ${releasePath} && npm ci --production --prefer-offline"`, { ignoreError: true });
  }

  // Atomic symlink switch on remote
  log('Switching symlink on remote...');
  exec(`${ssh} "ln -sfn ${releasePath} ${currentLink}.tmp && mv -Tf ${currentLink}.tmp ${currentLink}"`);

  // Cleanup old releases on remote
  exec(`${ssh} "cd ${deployPath}/releases && ls -1t | tail -n +6 | xargs -r rm -rf"`, { ignoreError: true });

  // Restart service on remote
  exec(`${ssh} "sudo systemctl restart app || pm2 restart all || true"`, { ignoreError: true });
}

async function cleanupOldReleases(releasesDir, keepCount) {
  if (!fs.existsSync(releasesDir)) return;

  const releases = fs.readdirSync(releasesDir)
    .map(name => ({
      name,
      path: path.join(releasesDir, name),
      time: fs.statSync(path.join(releasesDir, name)).mtimeMs,
    }))
    .sort((a, b) => b.time - a.time);

  const toRemove = releases.slice(keepCount);
  for (const release of toRemove) {
    log(`Removing old release: ${release.name}`);
    fs.rmSync(release.path, { recursive: true, force: true });
  }

  if (toRemove.length > 0) {
    log(`Cleaned up ${toRemove.length} old release(s)`);
  }
}

async function restartService() {
  // Try various process managers
  const restartCommands = [
    { name: 'pm2', cmd: 'pm2 restart ecosystem.config.js --env production', check: 'pm2 --version' },
    { name: 'systemctl', cmd: 'sudo systemctl restart app', check: 'systemctl --version' },
  ];

  for (const { name, cmd, check } of restartCommands) {
    const checkResult = exec(check, { silent: true, ignoreError: true });
    if (checkResult.success) {
      log(`Restarting application using ${name}...`);
      exec(cmd, { ignoreError: true });
      return;
    }
  }

  logWarning('No process manager detected - application may need manual restart');
}

// Health check after deployment
async function stageHealthCheck() {
  if (!CONFIG.healthCheckUrl) {
    logWarning('No health check URL configured - skipping health check');
    return;
  }

  log(`Health check URL: ${CONFIG.healthCheckUrl}`);
  log(`Timeout: ${CONFIG.healthCheckTimeout}ms, Interval: ${CONFIG.healthCheckInterval}ms`);

  const startTime = Date.now();
  let healthy = false;
  let lastError = '';

  while (Date.now() - startTime < CONFIG.healthCheckTimeout) {
    try {
      const result = exec(
        `curl -sf -o /dev/null -w '%{http_code}' --max-time 5 "${CONFIG.healthCheckUrl}"`,
        { silent: true }
      );

      const statusCode = parseInt(result.output.trim());
      if (statusCode >= 200 && statusCode < 300) {
        healthy = true;
        break;
      }

      lastError = `HTTP ${statusCode}`;
    } catch (error) {
      lastError = error.message;
    }

    log(`Waiting for health check... (${lastError})`);
    await new Promise(resolve => setTimeout(resolve, CONFIG.healthCheckInterval));
  }

  if (!healthy) {
    const errorMsg = `Health check failed after ${CONFIG.healthCheckTimeout}ms: ${lastError}`;
    logError(errorMsg);

    if (CONFIG.rollbackEnabled && pipelineState.previousDeployHash) {
      logWarning('Initiating automatic rollback...');
      await performRollback();
    }

    throw new PipelineError(errorMsg);
  }

  logSuccess('Health check passed');
}

// Rollback to previous deployment
async function performRollback() {
  const previousHash = pipelineState.previousDeployHash;
  if (!previousHash) {
    logError('No previous deployment to rollback to');
    return;
  }

  log(`Rolling back to: ${previousHash}`);

  if (!CONFIG.deployHost) {
    // Local rollback
    const deployPath = CONFIG.deployPath;
    const previousRelease = path.join(deployPath, 'releases', previousHash);
    const currentLink = path.join(deployPath, 'current');

    if (fs.existsSync(previousRelease)) {
      const tmpLink = `${currentLink}.tmp`;
      if (fs.existsSync(tmpLink)) fs.unlinkSync(tmpLink);
      fs.symlinkSync(previousRelease, tmpLink);
      fs.renameSync(tmpLink, currentLink);
      await restartService();
      logSuccess(`Rolled back to: ${previousHash}`);
    } else {
      logError(`Previous release not found: ${previousRelease}`);
    }
  } else {
    // Remote rollback
    const { deployHost, deployUser, deployPath } = CONFIG;
    const ssh = `ssh -o StrictHostKeyChecking=no ${deployUser}@${deployHost}`;
    const previousRelease = `${deployPath}/releases/${previousHash}`;
    const currentLink = `${deployPath}/current`;

    exec(`${ssh} "ln -sfn ${previousRelease} ${currentLink}.tmp && mv -Tf ${currentLink}.tmp ${currentLink}"`);
    exec(`${ssh} "sudo systemctl restart app || pm2 restart all || true"`, { ignoreError: true });
    logSuccess(`Rolled back to: ${previousHash}`);
  }
}

// Post-deploy notifications
async function stageNotify() {
  const totalDuration = ((Date.now() - pipelineState.startTime) / 1000).toFixed(2);
  const pkg = JSON.parse(fs.readFileSync('package.json', 'utf-8'));

  // Build summary
  const summary = {
    project: `${pkg.name}@${pkg.version}`,
    buildHash: pipelineState.buildHash,
    deployTarget: CONFIG.deployTarget,
    totalDuration: `${totalDuration}s`,
    stages: pipelineState.stages.map(s => ({
      name: s.name,
      status: s.status,
      duration: `${s.duration}s`,
    })),
    warnings: pipelineState.warnings,
    errors: pipelineState.errors,
  };

  // Write deploy log
  const logPath = path.join(CONFIG.artifactDir, 'deploy-log.json');
  fs.writeFileSync(logPath, JSON.stringify(summary, null, 2));
  log(`Deploy log written to: ${logPath}`);

  // Send Slack notification if configured
  if (CONFIG.slackWebhook) {
    try {
      const status = pipelineState.errors.length === 0 ? '✅ SUCCESS' : '❌ FAILED';
      const color = pipelineState.errors.length === 0 ? '#36a64f' : '#ff0000';

      const stagesSummary = pipelineState.stages
        .map(s => `${s.status === 'success' ? '✅' : '❌'} ${s.name} (${s.duration}s)`)
        .join('\n');

      const payload = JSON.stringify({
        attachments: [{
          color,
          title: `${status} | ${pkg.name}@${pkg.version} deployment`,
          fields: [
            { title: 'Build Hash', value: pipelineState.buildHash, short: true },
            { title: 'Target', value: CONFIG.deployTarget, short: true },
            { title: 'Duration', value: `${totalDuration}s`, short: true },
            { title: 'Stages', value: stagesSummary, short: false },
          ],
          footer: `CI/CD Pipeline | ${new Date().toISOString()}`,
        }],
      });

      exec(`curl -s -X POST -H 'Content-type: application/json' --data '${payload}' "${CONFIG.slackWebhook}"`, {
        silent: true,
        ignoreError: true,
        timeout: 10000,
      });

      log('Slack notification sent');
    } catch {
      logWarning('Failed to send Slack notification');
    }
  }
}

// Print final pipeline report
function printReport() {
  const totalDuration = ((Date.now() - pipelineState.startTime) / 1000).toFixed(2);

  console.log(`\n${colors.cyan}${'═'.repeat(60)}`);
  console.log('  📊 PIPELINE REPORT');
  console.log(`${'═'.repeat(60)}${colors.reset}\n`);

  for (const stage of pipelineState.stages) {
    const icon = stage.status === 'success' ? '✅' : stage.status === 'failed' ? '❌' : '⏸️';
    const color = stage.status === 'success' ? 'green' : stage.status === 'failed' ? 'red' : 'yellow';
    console.log(`  ${icon} ${colors[color]}${stage.name.padEnd(25)}${colors.reset} ${stage.duration}s`);
  }

  console.log(`\n  ⏱️  Total duration: ${colors.bold}${totalDuration}s${colors.reset}`);
  console.log(`  🔑 Build hash:     ${pipelineState.buildHash}`);

  if (pipelineState.warnings.length > 0) {
    console.log(`\n  ${colors.yellow}⚠️  Warnings (${pipelineState.warnings.length}):${colors.reset}`);
    pipelineState.warnings.forEach(w => console.log(`     - ${w}`));
  }

  if (pipelineState.errors.length > 0) {
    console.log(`\n  ${colors.red}❌ Errors (${pipelineState.errors.length}):${colors.reset}`);
    pipelineState.errors.forEach(e => console.log(`     - ${e}`));
  }

  console.log(`\n${colors.cyan}${'═'.repeat(60)}${colors.reset}\n`);
}

// Main pipeline execution
async function main() {
  console.log(`${colors.bold}${colors.cyan}`);
  console.log('  ╔══════════════════════════════════════════════════════╗');
  console.log('  ║         🚀 CI/CD PIPELINE - STARTING                ║');
  console.log('  ╚══════════════════════════════════════════════════════╝');
  console.log(`${colors.reset}\n`);

  log(`Pipeline started at ${new Date().toISOString()}`);
  log(`Working directory: ${process.cwd()}`);
  log(`Deploy target: ${CONFIG.deployTarget}`);
  log(`Max parallel jobs: ${CONFIG.maxParallelJobs}`);

  let exitCode = 0;

  try {
    // Stage 1: Preflight checks
    await runStage('Preflight Checks', stagePreflightChecks);

    // Stage 2: Install dependencies
    await runStage('Install Dependencies', stageInstallDependencies);

    // Stage 3 & 4: Run code quality and tests in parallel for speed
    await runStage('Quality & Tests', async () => {
      const results = await Promise.allSettled([
        stageCodeQuality(),
        stageRunTests(),
      ]);

      // Check if tests failed (critical)
      const testResult = results[1];
      if (testResult.status === 'rejected') {
        throw testResult.reason;
      }

      // Code quality is non-blocking but we log it
      const qualityResult = results[0];
      if (qualityResult.status === 'rejected') {
        logWarning(`Code quality checks failed: ${qualityResult.reason.message}`);
      }
    });

    // Stage 5: Build
    await runStage('Build', stageBuild);

    // Stage 6: Deploy
    await runStage('Deploy', stageDeploy);

    // Stage 7: Health Check
    await runStage('Health Check', stageHealthCheck);

    // Stage 8: Notify
    await runStage('Notify', stageNotify);

    log('🎉 Pipeline completed successfully!', 'green');

  } catch (error) {
    logError(`Pipeline failed: ${error.message}`);

    // Attempt notification even on failure
    try {
      await stageNotify();
    } catch {
      // Ignore notification errors during failure
    }

    exitCode = 1;
  } finally {
    printReport();
  }

  process.exit(exitCode);
}

// Handle uncaught errors
process.on('uncaughtException', (error) => {
  logError(`Uncaught exception: ${error.message}`);
  console.error(error.stack);
  printReport();
  process.exit(1);
});

process.on('unhandledRejection', (reason) => {
  logError(`Unhandled rejection: ${reason}`);
  printReport();
  process.exit(1);
});

// Handle signals for graceful shutdown
process.on('SIGINT', () => {
  logWarning('Pipeline interrupted by user (SIGINT)');
  printReport();
  process.exit(130);
});

process.on('SIGTERM', () => {
  logWarning('Pipeline terminated (SIGTERM)');
  printReport();
  process.exit(143);
});

// Run the pipeline
main();